// src/pages/AdminCourses.js
import React, { useEffect, useState } from 'react';
import api from '../services/api';
import { adminService } from '../services/admin';

// ─── Course Preview Modal ─────────────────────────────────────────────────────
const CoursePreviewModal = ({ course, onClose }) => {
  if (!course) return null;
  return (
    <div style={s.overlay} onClick={onClose}>
      <div style={s.modal} onClick={(e) => e.stopPropagation()}>
        <div style={s.modalHeader}>
          <h3 style={{ margin: 0 }}>📋 معاينة: {course.title}</h3>
          <button style={s.closeBtn} onClick={onClose}>✕</button>
        </div>
        <div style={s.modalBody}>
          {course.image_url && (
            <img src={course.image_url} alt={course.title}
              style={{ width:'100%', maxHeight:200, objectFit:'cover', borderRadius:8, marginBottom:12 }} />
          )}
          <div style={s.previewMeta}>
            <p><strong>المدرس:</strong> {course.instructor_name || course.instructor_email}</p>
            <p><strong>السعر:</strong> {course.price} EGP</p>
            <p><strong>الوصف:</strong> {course.description}</p>
            <p><strong>الأقسام:</strong> {course.total_sections} &nbsp;|&nbsp; <strong>الليكتشرات:</strong> {course.total_lectures}</p>
          </div>

          {course.sections && course.sections.length > 0 ? (
            <div>
              <h4 style={{ borderBottom:'1px solid #eee', paddingBottom:8 }}>محتوى الكورس</h4>
              {course.sections.map((sec, si) => (
                <div key={sec.id} style={s.previewSectionBox}>
                  <div style={s.sectionHeader}>
                    <strong>القسم {si + 1}: {sec.title}</strong>
                    <span style={s.badge}>{sec.lectures?.length || 0} ليكتشر</span>
                  </div>
                  {sec.description && <p style={{ margin:'4px 14px 8px', color:'#666', fontSize:13 }}>{sec.description}</p>}
                  {sec.lectures && sec.lectures.map((lec) => (
                    <div key={lec.id} style={s.lectureRow}>
                      <span style={s.lectureIcon}>
                        {lec.video_type === 'youtube' ? '▶ YT' : lec.video_type === 'vimeo' ? '▶ VM' : '🎬'}
                      </span>
                      <span style={{ flex:1 }}>{lec.title}</span>
                      <span style={s.statusBadge(lec.video_status)}>
                        {lec.video_status === 'approved' ? '✓ معتمد' : lec.video_status === 'rejected' ? '✗ مرفوض' : '⏳ معلق'}
                      </span>
                      {lec.duration_minutes > 0 && (
                        <span style={{ color:'#999', fontSize:12, marginLeft:8 }}>{lec.duration_minutes} د</span>
                      )}
                    </div>
                  ))}
                </div>
              ))}
            </div>
          ) : (
            <p style={{ color:'#999', textAlign:'center' }}>لا يوجد أقسام بعد</p>
          )}
        </div>
      </div>
    </div>
  );
};

// ─── Pending Courses tab ──────────────────────────────────────────────────────
const PendingCoursesTab = () => {
  const [courses, setCourses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [preview, setPreview] = useState(null);

  useEffect(() => {
    api.get('/courses/admin/courses/pending/')
      .then((res) => setCourses(res.data.results ?? res.data))
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  const loadPreview = async (courseId) => {
    try {
      const res = await api.get(`/courses/${courseId}/`);
      setPreview(res.data);
    } catch { alert('فشل تحميل المعاينة'); }
  };

  const handleApprove = async (id) => {
    try {
      await adminService.approveCourse(id);
      setCourses((prev) => prev.filter((c) => c.id !== id));
      if (preview?.id === id) setPreview(null);
    } catch { alert('فشل الموافقة'); }
  };

  const handleReject = async (id) => {
    try {
      await adminService.rejectCourse(id);
      setCourses((prev) => prev.filter((c) => c.id !== id));
      if (preview?.id === id) setPreview(null);
    } catch { alert('فشل الرفض'); }
  };

  if (loading) return <p style={s.msg}>Loading...</p>;
  if (!courses.length) return <p style={s.msg}>لا يوجد كورسات معلّقة 🎉</p>;

  return (
    <>
      <table style={s.table}>
        <thead>
          <tr>
            <th style={s.th}>العنوان</th>
            <th style={s.th}>المُدرّس</th>
            <th style={s.th}>السعر</th>
            <th style={s.th}>الإجراءات</th>
          </tr>
        </thead>
        <tbody>
          {courses.map((c) => (
            <tr key={c.id} style={s.tr}>
              <td style={s.td}>{c.title}</td>
              <td style={s.td}>{c.instructor_name || c.instructor_email}</td>
              <td style={s.td}>{c.price} EGP</td>
              <td style={s.td}>
                <button style={{ ...s.btn, ...s.previewBtn }} onClick={() => loadPreview(c.id)}>👁 معاينة</button>
                <button style={{ ...s.btn, ...s.approve }} onClick={() => handleApprove(c.id)}>✔ موافقة</button>
                <button style={{ ...s.btn, ...s.reject }}  onClick={() => handleReject(c.id)}>✖ رفض</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
      {preview && <CoursePreviewModal course={preview} onClose={() => setPreview(null)} />}
    </>
  );
};

// ─── Pending Lectures tab ─────────────────────────────────────────────────────
const PendingLecturesTab = () => {
  const [lectures, setLectures] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api.get('/courses/admin/lectures/pending/')
      .then((res) => setLectures(res.data.results ?? res.data))
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  const handleAction = async (id, action) => {
    try {
      await api.patch(`/courses/admin/lectures/${id}/approve/`, { action });
      setLectures((prev) => prev.filter((l) => l.id !== id));
    } catch { alert('فشل الإجراء'); }
  };

  if (loading) return <p style={s.msg}>Loading...</p>;
  if (!lectures.length) return <p style={s.msg}>لا يوجد فيديوهات معلّقة 🎉</p>;

  return (
    <table style={s.table}>
      <thead>
        <tr>
          <th style={s.th}>الليكتشر</th>
          <th style={s.th}>الكورس</th>
          <th style={s.th}>النوع</th>
          <th style={s.th}>S3 Key / URL</th>
          <th style={s.th}>الإجراءات</th>
        </tr>
      </thead>
      <tbody>
        {lectures.map((l) => (
          <tr key={l.id} style={s.tr}>
            <td style={s.td}>{l.title}</td>
            <td style={s.td}>{l.course?.title}</td>
            <td style={s.td}>
              <span style={s.typeBadge}>
                {l.video_type === 'youtube' ? '▶ YouTube' : l.video_type === 'vimeo' ? '▶ Vimeo' : '🎬 S3'}
              </span>
            </td>
            <td style={s.td}>
              <code style={{ fontSize:11, wordBreak:'break-all', color:'#555' }}>
                {l.s3_key || l.video_url || '-'}
              </code>
            </td>
            <td style={s.td}>
              <button style={{ ...s.btn, ...s.approve }} onClick={() => handleAction(l.id, 'approve')}>✔ موافقة</button>
              <button style={{ ...s.btn, ...s.reject }}  onClick={() => handleAction(l.id, 'reject')}>✖ رفض</button>
            </td>
          </tr>
        ))}
      </tbody>
    </table>
  );
};

// ─── Main ─────────────────────────────────────────────────────────────────────
const AdminCourses = () => {
  const [tab, setTab] = useState('courses');
  return (
    <div style={s.page}>
      <div style={s.card}>
        <h2 style={s.title}>🛡️ لوحة الأدمن</h2>
        <div style={s.tabs}>
          {['courses','lectures'].map((t) => (
            <button key={t} style={{ ...s.tabBtn, ...(tab===t ? s.tabActive : {}) }} onClick={() => setTab(t)}>
              {t === 'courses' ? '📚 كورسات معلّقة' : '🎬 فيديوهات معلّقة'}
            </button>
          ))}
        </div>
        {tab === 'courses'  && <PendingCoursesTab />}
        {tab === 'lectures' && <PendingLecturesTab />}
      </div>
    </div>
  );
};

// ─── Styles ───────────────────────────────────────────────────────────────────
const s = {
  page:      { background:'#f4f6f8', minHeight:'100vh', padding:'40px 20px' },
  card:      { background:'#fff', borderRadius:12, padding:25, boxShadow:'0 10px 25px rgba(0,0,0,0.08)' },
  title:     { marginBottom:20 },
  tabs:      { display:'flex', gap:10, marginBottom:20 },
  tabBtn:    { padding:'9px 20px', borderRadius:8, border:'1px solid #ccc', background:'#f0f0f0', cursor:'pointer', fontWeight:500 },
  tabActive: { background:'#007bff', color:'#fff', border:'1px solid #007bff' },
  msg:       { textAlign:'center', color:'#999', padding:'30px 0' },
  table:     { width:'100%', borderCollapse:'collapse' },
  th:        { textAlign:'left', padding:12, borderBottom:'2px solid #eee', color:'#555', fontSize:13 },
  tr:        { borderBottom:'1px solid #f0f0f0' },
  td:        { padding:'10px 12px', fontSize:14 },
  btn:       { padding:'6px 12px', borderRadius:6, border:'none', cursor:'pointer', marginRight:6, fontWeight:500, fontSize:12 },
  approve:   { backgroundColor:'#28a745', color:'#fff' },
  reject:    { backgroundColor:'#dc3545', color:'#fff' },
  previewBtn:{ backgroundColor:'#6c757d', color:'#fff' },
  typeBadge: { background:'#e9ecef', padding:'2px 8px', borderRadius:4, fontSize:12 },
  // Modal
  overlay:   { position:'fixed', inset:0, background:'rgba(0,0,0,0.5)', display:'flex', alignItems:'center', justifyContent:'center', zIndex:1000 },
  modal:     { background:'#fff', borderRadius:12, width:'90%', maxWidth:650, maxHeight:'85vh', display:'flex', flexDirection:'column', overflow:'hidden', boxShadow:'0 20px 60px rgba(0,0,0,0.3)' },
  modalHeader:{ display:'flex', justifyContent:'space-between', alignItems:'center', padding:'16px 20px', borderBottom:'1px solid #eee', background:'#f8f9fa' },
  modalBody: { overflowY:'auto', padding:20 },
  closeBtn:  { background:'none', border:'none', fontSize:20, cursor:'pointer', color:'#666' },
  previewMeta:{ background:'#f8f9fa', borderRadius:8, padding:14, marginBottom:16 },
  previewSectionBox:{ border:'1px solid #e0e0e0', borderRadius:8, marginBottom:12, overflow:'hidden' },
  sectionHeader:{ background:'#e9ecef', padding:'10px 14px', display:'flex', justifyContent:'space-between', alignItems:'center' },
  badge:     { background:'#007bff', color:'#fff', borderRadius:10, padding:'2px 10px', fontSize:12 },
  lectureRow:{ display:'flex', alignItems:'center', gap:8, padding:'8px 14px', borderTop:'1px solid #f0f0f0' },
  lectureIcon:{ fontSize:13, color:'#666', minWidth:30 },
  statusBadge: (st) => ({
    fontSize:11, padding:'2px 8px', borderRadius:10, fontWeight:600,
    background: st==='approved' ? '#d4edda' : st==='rejected' ? '#f8d7da' : '#fff3cd',
    color:      st==='approved' ? '#155724' : st==='rejected' ? '#721c24' : '#856404',
  }),
};

export default AdminCourses;
